brain:
var s=context.state,a=context.action,m=context.memory;
var PI2=Math.PI*2,PI=Math.PI;
if(!m.t){m.t=0;m.lf=-99;}m.t++;
var angDiff=function(a,b){var d=(a-b)%PI2;if(d>PI)d-=PI2;if(d<-PI)d+=PI2;return d;};
var angTo=function(x1,y1,x2,y2){return Math.atan2(y2-y1,x2-x1);};
var myX=s.position.x,myY=s.position.y,myA=s.angle;
var dC=Math.sqrt((myX-450)*(myX-450)+(myY-450)*(myY-450));
var toC=s.angleToCenter;
var rem=context.round.remaining;
var prox=s.proximity[0]||{};
var enemy=false;
for(var i=0;i<s.scanner.robot.length;i++){
  var rb=s.scanner.robot[i];
  if(rb.active&&(!enemy||rb.range<enemy.range)) enemy=rb;
}
var eProj=s.scanner.projectile[0]||false;
a.desiredForce=s.maxForce;a.desiredScan=180;
if(rem<5){
  if(dC>8){a.desiredAngle=toC;a.desiredForce=s.maxForce;}
  else a.desiredForce=0;
}else if(rem<12){
  a.desiredAngle=toC;a.desiredForce=s.maxForce;
  if(dC<40)a.desiredForce=s.maxForce*0.15;
}else{
  if(prox.entityType=='wall'){
    a.desiredAngle=toC;a.desiredForce=s.maxForce;
  }else if(enemy){
    var range=enemy.range;
    var projSpeed=42;
    var tF=range/projSpeed;
    var pX=enemy.x+enemy.speed*Math.cos(enemy.angle)*tF;
    var pY=enemy.y+enemy.speed*Math.sin(enemy.angle)*tF;
    var lA=angTo(myX,myY,pX,pY);
    a.desiredAngle=lA;
    var aimErr=Math.abs(angDiff(myA,lA));
    var tgtW=Math.atan2(28,range);
    if(aimErr<tgtW&&(m.t-m.lf)>=30){
      a.desiredLaunch=true;m.lf=m.t;
    }
    a.desiredScan=Math.max(80,Math.min(300,range*0.8));
    if(range<100)a.desiredForce=-s.maxForce*0.3;
    else if(range>250)a.desiredForce=s.maxForce;
    else a.desiredForce=s.maxForce*0.5;
  }else{
    if(dC>250)a.desiredAngle=toC;
    else if(Math.random()<0.02){
      var spread=PI/3;
      a.desiredAngle=myA+(Math.random()*spread)-spread/2;
    }
  }
  if(eProj&&eProj.range<90){
    var inc=(eProj.angleFromRobot+PI)%PI2;
    var pD=Math.abs(angDiff(eProj.angle,inc));
    if(pD<0.5){
      var pL=eProj.angleFromRobot+PI/2;
      var pR=eProj.angleFromRobot-PI/2;
      var dL=Math.abs(angDiff(pL,toC));
      var dR=Math.abs(angDiff(pR,toC));
      a.desiredAngle=(dL<dR)?pL:pR;
      a.desiredForce=s.maxForce*0.7;
    }
  }
}
if(myX<55||myX>845||myY<55||myY>845){
  a.desiredAngle=toC;a.desiredForce=s.maxForce;
}
